parameters.jsCode:
const tourItem = $('Tour Found?').item.json;
const tour = tourItem.result || {};

let aiData = {};
const rawAiText = $('Basic LLM Chain').item.json.text;
if (typeof rawAiText === 'string') {
  try {
    aiData = JSON.parse(rawAiText);
  } catch (e) {
    aiData = {};
  }
}

// Match the goldmoon-video-api /render schema exactly:
//   scenes: [{ image_url }], scene_texts: ["..."], style/transition/text_animation optional.
const images = (tour.images || []).filter(Boolean).slice(0, 4);
const sceneTexts = [
  aiData.text_scene_1,
  aiData.text_scene_2,
  aiData.text_scene_3,
  aiData.text_scene_4,
].filter(Boolean);

if (images.length < 2) {
  throw new Error(`Tour ${tour._id} has fewer than 2 images; cannot render.`);
}

const finalTexts = sceneTexts.length >= 2
  ? sceneTexts.slice(0, images.length)
  : [tour.title || 'Discover Egypt', 'Book your tour now'];

// Category -> style pool. Each category maps to 2 fitting presets (not a
// single hardcoded one) so relevance is respected without losing per-render
// variety. Unknown/missing category = no style set = the API's own
// random.choice across all 10 presets kicks in, same as before.
const CATEGORY_STYLES = {
  nile_cruise: ['luxury_gold', 'golden_hour'],
  desert_safari: ['desert_safari', 'vintage_film'],
  ancient_historical: ['vintage_film', 'editorial_mono'],
  beach_red_sea: ['dreamy_soft', 'night_chill'],
  city_cultural: ['modern_vibe', 'minimal_clean'],
  luxury_vip: ['luxury_gold', 'cinematic_dark'],
  adventure: ['desert_safari', 'modern_vibe'],
};

function pickStyleForCategory(category) {
  const pool = CATEGORY_STYLES[String(category || '').trim().toLowerCase()];
  if (!pool || pool.length === 0) return undefined;
  return pool[Math.floor(Math.random() * pool.length)];
}

return [{
  json: {
    // Kept for later nodes (Sanity mutate) via node-reference expressions;
    // the /render API ignores unknown fields so this is safe to send as-is.
    tour_id: tour._id || '',
    video_title: aiData.video_title || tour.title || 'Goldmoon Tour',
    description: aiData.description || '',
    tags: aiData.tags || [],

    // Fields actually consumed by POST /render:
    scenes: images.map((url) => ({ image_url: url })),
    scene_texts: finalTexts,
    bg_music: aiData.music_mood || 'luxury_chill',
    website_url: 'https://www.goldmoontours.com/en',
    style: pickStyleForCategory(tour.category),

    // transition / text_animation deliberately omitted: the API picks a
    // random one of each when absent, so cuts and text entrances still
    // vary render to render even though style is now category-aware.
  },
}];
